#include <iostream>
#include <string>
#include <vector>

class DynString {
    char* m_data{};
    int m_length{};
    static inline int s_moves{0};
    static inline int s_copies{0};
public:
    DynString() = default;
    DynString(const char* str){
        m_length=0; while(str[m_length]!='\0') ++m_length;
        m_data=new char[m_length+1];
        for(int i=0;i<=m_length;++i) m_data[i]=str[i];
    }
    ~DynString(){ delete[] m_data; }
    DynString(const DynString& src): m_length{src.m_length}{
        ++s_copies;
        if(src.m_data){ m_data=new char[m_length+1]; for(int i=0;i<=m_length;++i) m_data[i]=src.m_data[i]; }
    }
    DynString& operator=(const DynString& src){
        if(this!=&src){ ++s_copies; delete[] m_data; m_length=src.m_length;
            if(src.m_data){ m_data=new char[m_length+1]; for(int i=0;i<=m_length;++i) m_data[i]=src.m_data[i]; } else m_data=nullptr; }
        return *this;
    }
    DynString(DynString&& src) noexcept : m_data{src.m_data}, m_length{src.m_length}{
        ++s_moves; src.m_data=nullptr; src.m_length=0;
    }
    DynString& operator=(DynString&& src) noexcept {
        if(this!=&src){ ++s_moves; delete[] m_data; m_data=src.m_data; m_length=src.m_length; src.m_data=nullptr; src.m_length=0; }
        return *this;
    }
    void setChar(int i,char c){ if(m_data&&i<m_length) m_data[i]=c; }
    void print() const { std::cout << (m_data?m_data:"empty") << '\n'; }
    static int moveCount(){ return s_moves; }
    static int copyCount(){ return s_copies; }
};

int main(){
    std::string word; int n{};
    std::cin >> word >> n;
    DynString original{ word.c_str() };
    std::vector<DynString> log; log.reserve(2*n);
    for(int i=0;i<n;++i) log.push_back(DynString{ word.c_str() });
    for(int i=0;i<n;++i) log.push_back(original);
    log.back().setChar(0,'*');
    std::cout << "moves: " << DynString::moveCount() << '\n';
    std::cout << "copies: " << DynString::copyCount() << '\n';
    log.front().print();
    log.back().print();
    original.print();
    return 0;
}

